interface ValidationError {
  field: string;
  message: string;
}

interface CreateUserInput {
  name: unknown;
  email: unknown;
  age: unknown;
}

const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export function validateCreateUser(body: CreateUserInput): ValidationError[] {
  const errors: ValidationError[] = [];

  if (typeof body.name !== 'string' || body.name.trim().length === 0) {
    errors.push({ field: 'name', message: 'Name is required and must be a non-empty string' });
  } else if (body.name.length > 100) {
    errors.push({ field: 'name', message: 'Name must be 100 characters or fewer' });
  }

  if (typeof body.email !== 'string' || !EMAIL_RE.test(body.email)) {
    errors.push({ field: 'email', message: 'A valid email address is required' });
  }

  if (typeof body.age !== 'number' || !Number.isInteger(body.age) || body.age < 0 || body.age > 150) {
    errors.push({ field: 'age', message: 'Age must be an integer between 0 and 150' });
  }

  return errors;
}

import { Request, Response } from 'express';
import { User } from '../models/User';
import { db } from '../db';
import { validateCreateUser } from '../validators/userValidator';

export async function createUser(req: Request, res: Response) {
  const errors = validateCreateUser(req.body);
  if (errors.length > 0) {
    res.status(400).json({ errors });
    return;
  }
  const { name, email, age } = req.body;
  const user = new User(name, email, age);
  const id = await db.users.insert(user);
  res.status(201).json({ id, ...user });
}

